package org.apache.commons.math.distribution;

import io.cucumber.junit.Cucumber;
import io.cucumber.junit.CucumberOptions;
import org.junit.runner.RunWith;

@RunWith(Cucumber.class)
@CucumberOptions(
        features = "src/test/resources/requirement.feature",
        glue = "org.apache.commons.math.distribution.steps",
        plugin = {"pretty", "html:target/cucumber-reports"}
)
public class CucumberTest {
    // This is just a runner class, all configuration is in the annotations
}

package org.apache.commons.math.distribution.steps;

import io.cucumber.java.en.Given;
import io.cucumber.java.en.When;
import io.cucumber.java.en.Then;
import org.apache.commons.math.distribution.NormalDistribution;
import org.apache.commons.math.distribution.NormalDistributionImpl;
import static org.junit.Assert.*;

public class StepDefs {
    private NormalDistribution normalDistribution;
    private double result;
    private Exception thrownException;

    @Given("a Normal Distribution with mean 0.0 and standard distribution 1.0")
    public void a_Normal_Distribution_with_mean_0_0_and_standard_deviation_1_0() {
        normalDistribution = new NormalDistributionImpl(0.0, 1.0);
    }

    @When("I calculate the cumulative probability for {double}")
    public void i_calculate_the_cumulative_probability_for(double value) {
        try {
            thrownException = null;
            result = normalDistribution.cumulativeProbability(value);
        } catch (Exception e) {
            thrownException = e;
        }
    }

    @Then("the result should be {double}")
    public void the_result_should_be(double expected) {
        assertEquals(expected, result, 1e-10);
    }

    @Then("the calculation should not throw an exception")
    public void the_calculation_should_not_throw_an_exception() {
        assertNull("Expected no exception but got: " + thrownException, thrownException);
    }
}

